CREATE OR REPLACE FUNCTION public.update_roster_entry(p_roster_id uuid, p_class_ids jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_role text;
  v_email text;
  v_teacher_id uuid;
  v_class_id uuid;
  v_profile_id uuid;
  v_class_ids uuid[];
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required.';
  END IF;

  -- Get roster details
  SELECT role, email, profile_id INTO v_role, v_email, v_profile_id
  FROM public.roster
  WHERE id = p_roster_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Roster entry not found.';
  END IF;

  -- Convert jsonb array to uuid[]
  v_class_ids := ARRAY(SELECT jsonb_array_elements_text(p_class_ids)::uuid);

  -- Update class_ids in roster
  UPDATE public.roster
  SET class_ids = v_class_ids
  WHERE id = p_roster_id;

  -- Apply live updates to current mappings
  IF v_role = 'student' THEN
    -- If already logged in (has profile), update/recreate their enrollments
    IF v_profile_id IS NOT NULL THEN
      -- Delete old enrollments
      DELETE FROM public.enrollments
      WHERE student_id = v_profile_id;

      -- Create new enrollments
      FOREACH v_class_id IN ARRAY v_class_ids
      LOOP
        INSERT INTO public.enrollments (student_id, offering_id, total_classes)
        VALUES (v_profile_id, v_class_id, 48);
      END LOOP;
    END IF;
  ELSIF v_role = 'teacher' THEN
    -- Find teacher ID (could be auth ID if logged in, or generated ID if pending)
    SELECT id INTO v_teacher_id
    FROM public.teachers
    WHERE email = v_email
    LIMIT 1;

    IF v_teacher_id IS NOT NULL THEN
      -- Clear teacher assignment from offerings previously owned by this teacher
      UPDATE public.class_offerings
      SET teacher_id = NULL
      WHERE teacher_id = v_teacher_id;

      -- Assign new offerings
      FOREACH v_class_id IN ARRAY v_class_ids
      LOOP
        UPDATE public.class_offerings
        SET teacher_id = v_teacher_id
        WHERE id = v_class_id;
      END LOOP;
    END IF;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.delete_from_roster(p_roster_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_role text;
  v_email text;
  v_profile_id uuid;
  v_teacher_id uuid;
BEGIN
  -- Security check: only admins can call delete
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required.';
  END IF;

  -- 1. Check if record exists in roster table
  SELECT role, email, profile_id INTO v_role, v_email, v_profile_id
  FROM public.roster
  WHERE id = p_roster_id;

  -- 2. If not in roster, check if p_roster_id is directly a profile_id
  IF NOT FOUND THEN
    SELECT role, id INTO v_role, v_profile_id
    FROM public.profiles
    WHERE id = p_roster_id;
    
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Account entry not found.';
    END IF;
  END IF;

  -- Enforce admin delete prevention (Protected Accounts)
  IF v_role = 'admin' THEN
    RAISE EXCEPTION 'Access denied: Protected administrator accounts cannot be removed.';
  END IF;

  -- Try resolving profile_id via auth.users if currently null
  IF v_profile_id IS NULL AND v_email IS NOT NULL THEN
    SELECT id INTO v_profile_id
    FROM public.profiles
    WHERE id IN (SELECT id FROM auth.users WHERE LOWER(email) = LOWER(v_email))
    LIMIT 1;
  END IF;

  -- ── STUDENT CASCADING CLEANUP ──
  IF v_role = 'student' THEN
    IF v_profile_id IS NOT NULL THEN
      -- Clean fee audit and status records first
      DELETE FROM public.fee_audit_trail WHERE student_id = v_profile_id OR changed_by = v_profile_id;
      DELETE FROM public.fee_statuses WHERE student_id = v_profile_id;
      
      -- Clean operational learning records
      DELETE FROM public.enrollments WHERE student_id = v_profile_id;
      DELETE FROM public.attendance WHERE student_id = v_profile_id;
      DELETE FROM public.study_sessions WHERE student_id = v_profile_id;
      DELETE FROM public.notes WHERE uploaded_by = v_profile_id;
      
      -- Delete profile and auth user
      DELETE FROM public.profiles WHERE id = v_profile_id;
      DELETE FROM auth.users WHERE id = v_profile_id;
    END IF;
    IF v_email IS NOT NULL THEN
      DELETE FROM auth.users WHERE LOWER(email) = LOWER(v_email);
    END IF;

  -- ── TEACHER CASCADING CLEANUP ──
  ELSIF v_role = 'teacher' THEN
    SELECT id INTO v_teacher_id FROM public.teachers WHERE LOWER(email) = LOWER(v_email) OR id = p_roster_id OR id = v_profile_id LIMIT 1;
    IF v_teacher_id IS NOT NULL THEN
      -- Unlink schedule class offerings so timetable schedule stays intact
      UPDATE public.class_offerings SET teacher_id = NULL WHERE teacher_id = v_teacher_id;
      DELETE FROM public.teachers WHERE id = v_teacher_id;
    END IF;
    IF v_profile_id IS NOT NULL THEN
      DELETE FROM public.notes WHERE uploaded_by = v_profile_id;
      DELETE FROM public.profiles WHERE id = v_profile_id;
      DELETE FROM auth.users WHERE id = v_profile_id;
    END IF;
    IF v_email IS NOT NULL THEN
      DELETE FROM auth.users WHERE LOWER(email) = LOWER(v_email);
    END IF;
  END IF;

  -- 3. Remove roster record itself
  DELETE FROM public.roster WHERE id = p_roster_id OR profile_id = v_profile_id OR (v_email IS NOT NULL AND LOWER(email) = LOWER(v_email));
END;
$function$

CREATE OR REPLACE FUNCTION public.prevent_role_escalation()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- Privilege escalation guard
  IF NOT public.is_admin() AND NEW.role IS DISTINCT FROM OLD.role THEN
    RAISE EXCEPTION 'Privilege escalation blocked: only admins can change roles.';
  END IF;

  -- Reset onboarding_complete when the user's role transitions TO student FROM any other role
  IF NEW.role = 'student' AND OLD.role IS DISTINCT FROM NEW.role THEN
    NEW.onboarding_complete := false;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.add_to_roster(p_email text, p_full_name text, p_role text, p_class_ids jsonb, p_phone text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
      DECLARE
        v_roster_id uuid;
        v_profile_id uuid;
        v_class_id uuid;
        v_class_ids uuid[];
      BEGIN
        -- Server-side Admin security check
        IF NOT public.is_admin() THEN
          RAISE EXCEPTION 'Access denied: Admin role required.';
        END IF;

        -- Validate role
        IF p_role = 'student' THEN
          RAISE EXCEPTION 'Pre-provisioning of students is not allowed.';
        END IF;

        IF p_role NOT IN ('student', 'teacher') THEN
          RAISE EXCEPTION 'Invalid role. Must be student or teacher.';
        END IF;

        -- Validate email uniqueness in roster
        IF EXISTS (SELECT 1 FROM public.roster WHERE email = LOWER(p_email)) THEN
          RAISE EXCEPTION 'Email is already registered in the roster.';
        END IF;

        -- Validate email uniqueness in profiles
        IF EXISTS (SELECT 1 FROM public.profiles p JOIN auth.users u ON p.id = u.id WHERE u.email = LOWER(p_email)) THEN
          RAISE EXCEPTION 'A user profile with this email already exists.';
        END IF;

        -- Convert jsonb array to uuid[]
        v_class_ids := ARRAY(SELECT jsonb_array_elements_text(p_class_ids)::uuid);

        -- Generate profile ID upfront
        v_profile_id := gen_random_uuid();

        -- Insert profile
        INSERT INTO public.profiles (id, role, full_name, phone)
        VALUES (v_profile_id, p_role, p_full_name, p_phone);

        -- Insert into roster linking the profile
        INSERT INTO public.roster (email, full_name, role, class_ids, profile_id)
        VALUES (LOWER(p_email), p_full_name, p_role, v_class_ids, v_profile_id)
        RETURNING id INTO v_roster_id;

        -- If it's a student, enroll them in classes
        IF p_role = 'student' THEN
          FOREACH v_class_id IN ARRAY v_class_ids
          LOOP
            INSERT INTO public.enrollments (student_id, offering_id, total_classes)
            VALUES (v_profile_id, v_class_id, 48);
          END LOOP;
        -- If it's a teacher, pre-provision them in the teachers table and assign class offerings
        ELSIF p_role = 'teacher' THEN
          INSERT INTO public.teachers (id, full_name, email, is_active, joining_date)
          VALUES (v_profile_id, p_full_name, LOWER(p_email), TRUE, CURRENT_DATE);

          FOREACH v_class_id IN ARRAY v_class_ids
          LOOP
            UPDATE public.class_offerings
            SET teacher_id = v_profile_id
            WHERE id = v_class_id;
          END LOOP;
        END IF;

        RETURN v_roster_id;
      END;
      $function$

CREATE OR REPLACE FUNCTION public.handle_roster_profile_link()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_old_id uuid;
  v_new_id uuid;
  v_total integer := 0;
  v_rows integer;
BEGIN
  v_old_id := OLD.profile_id;
  v_new_id := NEW.profile_id;

  -- Guard: Only proceed if profile_id has transitioned from a placeholder/different ID
  IF v_old_id IS NULL OR v_new_id IS NULL OR v_old_id = v_new_id THEN
    RETURN NEW;
  END IF;

  RAISE NOTICE '[handle_roster_profile_link] Migrating % → % for %', v_old_id, v_new_id, NEW.email;

  -- ── Migrate every known FK column referencing profiles(id) ──

  -- enrollments.student_id
  UPDATE public.enrollments SET student_id = v_new_id WHERE student_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- attendance.student_id
  UPDATE public.attendance SET student_id = v_new_id WHERE student_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- study_sessions.student_id
  UPDATE public.study_sessions SET student_id = v_new_id WHERE student_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- notes.uploaded_by
  UPDATE public.notes SET uploaded_by = v_new_id WHERE uploaded_by = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- fee_statuses.student_id (UNIQUE constraint — remove conflict first)
  IF EXISTS (SELECT 1 FROM public.fee_statuses WHERE student_id = v_old_id) THEN
    DELETE FROM public.fee_statuses WHERE student_id = v_new_id;
    UPDATE public.fee_statuses SET student_id = v_new_id WHERE student_id = v_old_id;
    GET DIAGNOSTICS v_rows = ROW_COUNT;
    v_total := v_total + v_rows;
  END IF;

  -- fee_audit_trail.student_id
  UPDATE public.fee_audit_trail SET student_id = v_new_id WHERE student_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- fee_audit_trail.changed_by
  UPDATE public.fee_audit_trail SET changed_by = v_new_id WHERE changed_by = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- announcements.created_by
  UPDATE public.announcements SET created_by = v_new_id WHERE created_by = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- notifications.recipient_id
  UPDATE public.notifications SET recipient_id = v_new_id WHERE recipient_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- teachers.id (PK — re-key by INSERT new + DELETE old)
  -- Crucially, we OMIT the phone column since public.teachers has no phone column
  IF EXISTS (SELECT 1 FROM public.teachers WHERE id = v_old_id) THEN
    INSERT INTO public.teachers (id, full_name, email, is_active, joining_date, avatar_url, created_at)
    SELECT v_new_id, full_name, email, is_active, joining_date, avatar_url, created_at
    FROM public.teachers WHERE id = v_old_id
    ON CONFLICT (id) DO UPDATE SET
      full_name = EXCLUDED.full_name,
      email = EXCLUDED.email,
      is_active = EXCLUDED.is_active;
    GET DIAGNOSTICS v_rows = ROW_COUNT;
    v_total := v_total + v_rows;
  END IF;

  -- class_offerings.teacher_id
  UPDATE public.class_offerings SET teacher_id = v_new_id WHERE teacher_id = v_old_id;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_total := v_total + v_rows;

  -- Now safe to delete old teacher row since class_offerings no longer references it
  IF EXISTS (SELECT 1 FROM public.teachers WHERE id = v_old_id) THEN
    DELETE FROM public.teachers WHERE id = v_old_id;
  END IF;

  -- Delete the orphaned old placeholder profile
  DELETE FROM public.profiles WHERE id = v_old_id;

  RAISE NOTICE '[handle_roster_profile_link] ✅ Migrated % FK rows, deleted orphan %', v_total, v_old_id;

  RETURN NEW;
END;
$function$
